export default App;

import { useState, useEffect } from 'react';
import { Routes, Route, useLocation } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';
import { useAudio } from './hooks/useAudio';
import { useTables } from './hooks/useTables';
import { useInventory } from './hooks/useInventory';
import { CardProvider } from './contexts/CardContext';
import Login from './components/Login';
import Header from './components/Header';
import TableGrid from './components/TableGrid';
import StatusDashboard from './components/StatusDashboard';
import ShoppingList from './components/ShoppingList';
import ActivityLog from './components/ActivityLog';
import RequirementsCard from './components/RequirementsCard';
import FeaturesCard from './components/FeaturesCard';
import FooterLinks from './components/FooterLinks';
import AdminPanel from './components/AdminPanel';
import Manual from './components/Manual';
import Inventory from './components/Inventory';
import MultiPage1 from './components/MultiPage1';
import CleaningChecklist from './components/CleaningChecklist';
import CleaningCard from './components/CleaningCard';
import ProductForm from './components/ProductForm'; // <-- Existing import
import ProductList from './components/ProductList'; // <-- New import
import ClientSuggestions from './components/ClientSuggestions'; // <-- Existing import
import ProductDecisions from './components/ProductDecisions'; // <-- New import
import ProductReporting from './components/ProductReporting'; // <-- New import
import getAppVersionInfo from './versionInfo'; // Import the version info module

import { useSettings } from './hooks/useSettings';

function App() {
  const { user, userData, loading, loginEmail, loginAnonymously, logout } = useAuth();
  const { tables } = useTables();
  const { inventory } = useInventory();
  const { settings } = useSettings();
  const { isAudioEnabled, initAudio, playNotificationSound } = useAudio(tables, inventory, settings);

  const [showAdminView, setShowAdminView] = useState(false); // State for admin view
  const appVersionInfo = getAppVersionInfo(); // Get the app version information
  const location = useLocation(); // Get current location

  // Determine currentPage based on pathname
  let currentPage = '';
  if (location.pathname === '/') {
    currentPage = 'dashboard';
  } else if (location.pathname === '/cleaning') {
    currentPage = 'cleaning';
  }
  // Add more conditions for other pages as needed

  // ÉTAPE 1 : Attendre que Firebase réponde
  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center">
        <div className="text-[#d4af37] animate-pulse font-bold uppercase tracking-[0.3em]">
          Mictlán...
        </div>
      </div>
    );
  }

  // ÉTAPE 2 : Si pas d'utilisateur, on force l'affichage du Login uniquement
  if (!user) {
    return <Login onLogin={loginEmail} onAnonymousLogin={loginAnonymously} />;
  }

  // ÉTAPE 3 : Si connecté, on affiche le Dashboard
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-200">
      <Header 
        user={user} 
        userData={userData}
        onLogout={logout} 
        isAudioEnabled={isAudioEnabled} 
        onEnableAudio={initAudio} 
        showAdminView={showAdminView}
        setShowAdminView={setShowAdminView}
      />
      <Manual userData={userData} currentPage={currentPage} showAdminView={showAdminView} />
      <CardProvider>
        <Routes>
          <Route path="/" element={
            <main className="container mx-auto py-8 flex flex-col gap-12 px-4">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <TableGrid 
                  playNotificationSound={playNotificationSound} 
                  showAdminView={showAdminView}
                  userData={userData}
                />
                <StatusDashboard />
                <Inventory user={user} userData={userData} showAdminView={showAdminView} />
                <ShoppingList />
                <ActivityLog />
                <CleaningCard />
                <ClientSuggestions />
                <ProductDecisions /> {/* <-- New component */} {/* <-- New component */}
              </div>
              <FooterLinks versionInfo={appVersionInfo.fullVersion} /> {/* Pass version info to FooterLinks */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {userData?.role === 'admin' && showAdminView && <AdminPanel />}
                {userData?.role === 'admin' && showAdminView && <FeaturesCard />}
                {userData?.role === 'admin' && showAdminView && <RequirementsCard />}
                {userData?.role === 'admin' && showAdminView && <ProductForm />}
                {userData?.role === 'admin' && showAdminView && <ProductList />}
                {userData?.role === 'admin' && showAdminView && <ProductReporting />}
              </div>
            </main>
          } />
          <Route path="/multipage1" element={<MultiPage1 />} />
          <Route path="/cleaning" element={<CleaningChecklist userData={userData} showAdminView={showAdminView} />} />
        </Routes>
      </CardProvider>
    </div>
  );
}

export default App;

import { useState, useEffect, useCallback } from 'react';
import { getTableSettings, updateTableSettings } from '../firebase/settingsActions';
import { db } from '../firebase/config';
import { doc, onSnapshot } from 'firebase/firestore';

export function useSettings() {
  const [settings, setSettings] = useState({ inactivityTimeout: 10 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const settingsDocRef = doc(db, 'settings', 'tables');
    const unsubscribe = onSnapshot(settingsDocRef, (docSnap) => {
      if (docSnap.exists()) {
        setSettings(docSnap.data());
      } else {
        // This will be created by getTableSettings if it doesn't exist
        getTableSettings().then(setSettings);
      }
      setLoading(false);
    }, (error) => {
      console.error("Erreur listening to settings:", error);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const updateSettings = useCallback(async (newSettings) => {
    await updateTableSettings(newSettings);
  }, []);

  return { settings, loading, updateSettings };
}

import { useState, useEffect } from 'react';
import { Volume2, VolumeX } from 'lucide-react';

// Fonction pour capitaliser la première lettre
const capitalize = (s) => s.charAt(0).toUpperCase() + s.slice(1);

export default function Header({ user, userData, onLogout, isAudioEnabled, onEnableAudio, showAdminView, setShowAdminView }) {
  const prNumber = import.meta.env.VITE_GITHUB_PR_NUMBER;
  const currentMode = import.meta.env.MODE;
  const version = import.meta.env.VITE_APP_VERSION;

  const [dateTimeString, setDateTimeString] = useState('');
  const [weatherData, setWeatherData] = useState(null);

  // Effet pour récupérer les données météo
  useEffect(() => {
    const fetchWeather = async () => {
      const apiKey = import.meta.env.VITE_OPENWEATHER_API_KEY;
      const city = 'Paris,FR';

      if (!apiKey) {
        console.error("Clé API OpenWeatherMap non trouvée. Assurez-vous d'avoir un fichier .env.local avec VITE_OPENWEATHER_API_KEY.");
        setWeatherData({ description: 'Erreur config', temperature: 'N/A' });
        return;
      }

      try {
        const response = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${apiKey}&units=metric&lang=fr`);
        if (!response.ok) {
          throw new Error('Réponse réseau non OK');
        }
        const data = await response.json();
        setWeatherData({
          description: data.weather[0].description,
          temperature: Math.round(data.main.temp),
        });
      } catch (error) {
        console.error("Erreur de récupération météo:", error);
        setWeatherData({ description: 'Erreur API', temperature: 'N/A' });
      }
    };

    fetchWeather(); // Appel initial
    const interval = setInterval(fetchWeather, 600000); // Rafraîchir toutes les 10 minutes

    return () => clearInterval(interval); // Nettoyage
  }, []);

  // Effet pour mettre à jour l'affichage de l'heure et de la météo
  useEffect(() => {
    const formatDateTime = () => {
      const now = new Date();
      const datePart = new Intl.DateTimeFormat('fr-FR', {
        weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
      }).format(now);
      const timePart = new Intl.DateTimeFormat('fr-FR', {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false,
      }).format(now).replace(/:/g, 'h');

      let weatherString = 'Chargement de la météo...';
      if (weatherData) {
        weatherString = `${capitalize(weatherData.description)} - ${weatherData.temperature}°C`;
      }
      
      return `${capitalize(datePart)} - ${timePart} - ${weatherString}`;
    };

    const intervalId = setInterval(() => {
      setDateTimeString(formatDateTime());
    }, 1000);

    return () => clearInterval(intervalId);
  }, [weatherData]);

  let environmentText = '';
  if (currentMode === 'development') {
    environmentText = 'local dev realtime modifications';
  } else if (currentMode === 'staging') {
    if (prNumber) {
      environmentText = `staging site PR#${prNumber}`;
    } else {
      environmentText = 'local staging build';
    }
  } else if (currentMode === 'production' && window.location.hostname === 'localhost') {
    environmentText = 'local production build';
  }

  const versionDisplay = `version ${version}${environmentText ? ` - ${environmentText}` : ''}`;

  return (
    <header className="text-center mb-4 sm:mb-8 relative flex flex-col items-center">
      <div className="text-gray-500 text-sm mb-1">
        {versionDisplay}
      </div>
      <img src="/mictlan-logo.png" alt="Mictlan Logo" className="w-24 h-auto" style={{ height: '80px', width: 'auto' }} />
      <div className="absolute top-0 right-0 p-2">
        <button onClick={onEnableAudio} className="p-2 text-white">
          {isAudioEnabled ? <Volume2 /> : <VolumeX className="text-red-500" />}
        </button>
      </div>

      <h1 className="text-3xl font-bold text-yellow-500 mb-2">
        Dashboard Le Mictlan
      </h1>
      <p className="text-gray-400 text-sm font-mono mt-2">{dateTimeString}</p> {/* Ajout de la date/heure/météo */}

      <div className="text-white">
        {user ? (
          <div className="flex flex-col items-center gap-2">
            <span className="text-green-400 text-sm">Connecté: {user.isAnonymous ? 'Anonyme' : user.email}</span>
            {userData?.role === 'admin' && (
              <div className="flex items-center gap-2 mt-2">
                <input
                  type="checkbox"
                  id="adminView"
                  checked={showAdminView}
                  onChange={(e) => setShowAdminView(e.target.checked)}
                  className="form-checkbox h-4 w-4 text-mictlan-gold bg-gray-800 border-gray-600 rounded focus:ring-mictlan-gold"
                />
                <label htmlFor="adminView" className="text-xs text-gray-400">Voir les parties d'admin</label>
              </div>
            )}
            <button onClick={onLogout} className="text-xs text-gray-400 underline">Déconnexion</button>
          </div>
        ) : (
          <span className="text-red-400 text-sm">Déconnecté</span>
        )}
      </div>
    </header>
  );
}

